const raw = $input.first().json.output || $input.first().json.text || '';

// 1. Limpeza inicial de Markdown
let texto = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

// 2. Tenta encontrar um bloco de JSON dentro da resposta
const jsonMatch = texto.match(/\{[\s\S]*\}/);

if (jsonMatch) {
  // CASO A: Encontrou um JSON (comportamento normal)
  try {
    const parsed = JSON.parse(jsonMatch[0].trim());
    return [{
      json: {
        mensagem_cliente:      parsed.mensagem_cliente      || 'Como posso ajudar?',
        carrinho:              Array.isArray(parsed.carrinho) ? parsed.carrinho : [],
        valor_total:           typeof parsed.valor_total === 'number' ? parsed.valor_total : 0,
        modalidade:            parsed.modalidade            || 'entrega',
        pronto_para_pagamento: parsed.pronto_para_pagamento === true,
        chamar_humano:         parsed.chamar_humano         === true
      }
    }];
  } catch (e) {
    // Se o JSON estiver malformado, cai no fallback abaixo
    console.error('[Code_Parser] JSON Malformado:', e.message);
  }
}

// CASO B: NÃ£o encontrou JSON ou falhou no parse (Fallback Inteligente)
// Se a IA mandou apenas texto puro, usamos esse texto como a mensagem para o cliente
return [{
  json: {
    mensagem_cliente:      texto || 'Como posso ajudar? ðŸ˜Š',
    carrinho:              [],
    valor_total:           0,
    modalidade:            'entrega',
    pronto_para_pagamento: false,
    chamar_humano:         false,
    _parser_fallback:      true // Marcador interno para log
  }
}];

