  const elem = result.rows[0].elements[0];
  if (elem.status === 'OK') {
    distanciaKm = parseFloat((elem.distance.value / 1000).toFixed(2));
    taxa = parseFloat((distanciaKm * loc.valor_por_km).toFixed(2));
  } else { erro = true; }
