const raw = $input.first().json.content || $input.first().json.text || '';
const clean = raw.replace(/```json\s*/gi,'').replace(/```\s*/gi,'').trim();
const match = clean.match(/\{[\s\S]*\}/);
try {
  const parsed = JSON.parse(match ? match[0] : clean);
  return [{ json: { valido: parsed.valido === true, motivo: parsed.motivo || '' } }];
} catch(e) {
