if (jsonMatch) texto = jsonMatch[0].trim();

try {
  const parsed = JSON.parse(texto);

  // Validate required fields â€” fill defaults if missing
  return [{
    json: {
      mensagem_cliente:     parsed.mensagem_cliente     || 'Como posso ajudar?',
      carrinho:             Array.isArray(parsed.carrinho) ? parsed.carrinho : [],
      valor_total:          typeof parsed.valor_total === 'number' ? parsed.valor_total : 0,
      modalidade:           parsed.modalidade            || 'entrega',
      pronto_para_pagamento: parsed.pronto_para_pagamento === true,
      chamar_humano:        parsed.chamar_humano         === true,
    }
  }];
} catch(e) {
  // Log the raw output to help debug
  console.error('[Code_Parser] JSON parse error:', e.message);
  console.error('[Code_Parser] Raw output was:', raw.slice(0, 500));

  // Return safe fallback â€” do NOT expose error to client
  return [{
